"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[905],{3985:function(e,t,o){o.d(t,{K4:function(){return r},P5:function(){return a},UL:function(){return n}});let n={community:"#3b82f6","consumer-affairs":"#f59e0b","education-1":"#10b981","education-2":"#10b981","employment-1":"#8b5cf6","employment-2":"#8b5cf6",financial:"#ef4444","social-services":"#ec4899"},a={community:"Community","consumer-affairs":"Consumer Affairs","education-1":"Education","education-2":"Education","employment-1":"Employment","employment-2":"Employment",financial:"Financial","social-services":"Social Services"},r={foundation:"#3b82f6",expansion:"#10b981",intensive:"#f59e0b",mock:"#ef4444"}},4628:function(e){e.exports=JSON.parse('[{"id":"community","domain":"Community","title":"Animal Protection - Neighbour\'s Dog","scenario":"This dialogue is a phone conversation between a resident and an English-speaking staff member of the animal protection centre. The resident is calling the animal protection centre to discuss the welfare of their neighbour\'s dog.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 41 #2060","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello. This is the animal protection society. I\'m Harry. How can I help you today?","wordCount":15},{"number":2,"speaker":"MANDARIN","text":"您好，我觉得我的邻居在虐待他们的狗。我不知道该怎么办。","translation":"Hello. I think my neighbours are mistreating their dog. I\'m not sure what to do.","wordCount":15},{"number":3,"speaker":"ENGLISH","text":"It\'s good that you have called us. Could you tell me why you think the dog is being mistreated?","wordCount":19},{"number":4,"speaker":"MANDARIN","text":"它一直在叫。我想可能是狗不听话。但是当我从围墙上看邻居的后院时，我发现狗根本没有水喝。","translation":"It barks all the time. I thought it was behaving badly. But I looked over the fence into the back yard, and I saw it didn\'t have any water to drink.","wordCount":31},{"number":5,"speaker":"ENGLISH","text":"I see. That\'s not good. Dogs need to have drinking water available all the time. Have you noticed anything else wrong?","wordCount":21},{"number":6,"speaker":"MANDARIN","text":"是的。那条狗很大，但是很瘦。我还能看到它身上的肋骨。狗毛暗淡无光，并缠在一起。我觉得狗很不健康。","translation":"Yes. The dog is quite big, but it\'s very thin. I can see its ribs. Its coat is dull and matted. I don\'t think it looks healthy.","wordCount":27},{"number":7,"speaker":"ENGLISH","text":"You shouldn\'t be able to see its ribs. It doesn\'t sound like it is in good condition. You might be right.","wordCount":21},{"number":8,"speaker":"MANDARIN","text":"我的邻居从来不去遛狗。我本想去敲他们的门，跟他们说一下，可又担心他们可能会不高兴。","translation":"My neighbours never take it for a walk either. I was going to knock on their door, but I thought they might get angry at me.","wordCount":26},{"number":9,"speaker":"ENGLISH","text":"It\'s best not to approach your neighbours. I will write up a report on what you have told me, and our protection officers will visit them.","wordCount":26},{"number":10,"speaker":"MANDARIN","text":"我不想让他们有什么麻烦，但是我确实担心那条狗。","translation":"I don\'t want them to get into trouble, but I am worried about the dog.","wordCount":15},{"number":11,"speaker":"ENGLISH","text":"Don\'t worry. If they are not mistreating the dog, they won\'t get into trouble. We will help them if they need more information on how to take care of the dog.","wordCount":31},{"number":12,"speaker":"MANDARIN","text":"这听起来很好。我希望动物保护工作人员能够尽快来看看。我很高兴跟您打了电话，万一那狗真的需要帮助。","translation":"That sounds good. I hope the protection officers will visit them soon. I\'m glad I called you, in case the dog does need help.","wordCount":24},{"number":13,"speaker":"ENGLISH","text":"I\'m sure they will come in the next few days. If you notice the situation getting worse in the meantime, call us back.","wordCount":23},{"number":14,"speaker":"MANDARIN","text":"我会的。谢谢您接听我的电话。","translation":"I will. Thank you for listening to me.","wordCount":8}],"totalWords":302},{"id":"consumer-affairs","domain":"Consumer Affairs","title":"Tree Trimming Company Complaint","scenario":"In this dialogue, a customer has paid a tree trimming company to remove six trees from their back yard. Simon, the English-speaking owner of the company, cut down four of the trees. He has not returned to complete the work. The customer calls Simon on the telephone to ask him to remove the last two trees.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 35 #2048","segments":[{"number":1,"speaker":"ENGLISH","text":"Good morning. This is Simon from the tree trimming company. How can I help you?","wordCount":15},{"number":2,"speaker":"MANDARIN","text":"西蒙，您好。三周前，您在我房子的后院砍了四棵大树。","translation":"Hello Simon. Three weeks ago, you cut down four large trees in the back yard of my house.","wordCount":18},{"number":3,"speaker":"ENGLISH","text":"Yes, I remember cutting down those trees. That was a hard job because the trees were so close to the fence.","wordCount":21},{"number":4,"speaker":"MANDARIN","text":"我付给您的钱是砍六棵树的。这个工作没完成，我不满意。","translation":"I paid you to cut down six trees. I\'m unhappy the job isn\'t finished.","wordCount":14},{"number":5,"speaker":"ENGLISH","text":"The job took much longer than I expected. I could only remove four trees.","wordCount":14},{"number":6,"speaker":"MANDARIN","text":"您答应会告诉我您什么时候回来完成这项工作。我一直在等您的电话。","translation":"You agreed to let me know when you could return to finish the work. I\'ve been waiting for your telephone call.","wordCount":21},{"number":7,"speaker":"ENGLISH","text":"I\'m sorry that I didn\'t call you. We\'ve been very busy. Let me look at my diary. I can come to your house in four weeks.","wordCount":26},{"number":8,"speaker":"MANDARIN","text":"我不想等那么久。我希望这项工作能在冬天到来之前完成。","translation":"I would prefer not to wait that long. I had hoped this work would be completed before the start of winter.","wordCount":21},{"number":9,"speaker":"ENGLISH","text":"Yes, I know. But the trees will be hard to remove because they are near the fence. It will take longer to do the work.","wordCount":25},{"number":10,"speaker":"MANDARIN","text":"我知道。但是最近有暴风雨。我担心如果风更大的话，树枝会掉到我的房子上。","translation":"I understand. But we\'ve had some storms recently. I\'m worried that the branches will fall on my house if we have more strong wind.","wordCount":24},{"number":11,"speaker":"ENGLISH","text":"Storms are forecasted next week. If the trees are unsafe, I will remove them before then.","wordCount":16},{"number":12,"speaker":"MANDARIN","text":"我想确保我的房子安全，不受损害。您这个星期什么时候过来都行，周末也可以。","translation":"I want to make sure my house is safe from damage. You can come any time this week or on the weekend.","wordCount":22},{"number":13,"speaker":"ENGLISH","text":"I\'ll come on Saturday from 2 p.m. to 5 p.m. If I don\'t finish the work, I\'ll need to return early next week.","wordCount":25},{"number":14,"speaker":"MANDARIN","text":"会不会从我邻居的后院能更容易够得到树呢？我可以问问看是否您可以到她的院子。","translation":"Would it be easier to reach the trees from my neighbour\'s back yard? I could ask if you could go into her yard.","wordCount":23},{"number":15,"speaker":"ENGLISH","text":"That\'s a good idea! I apologise for the delay. I\'ll see you on Saturday at 2 p.m.","wordCount":18}],"totalWords":303},{"id":"education-1","domain":"Education","title":"School Enrolment for Daughter","scenario":"This dialogue is an interview between a mother and a school Principal, Ms Karen Black. The mother is seeking information on how to process her daughter\'s enrolment at the school.","englishSpeakerGender":"Female","loteSpeakerGender":"Female","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Good afternoon. I am Karen Black, the Principal. Thank you for your interest in enrolling your daughter at our school.","wordCount":20},{"number":2,"speaker":"MANDARIN","text":"下午好，布莱克女士！非常感谢你安排这次面试！我们刚到澳洲几个月，我希望我女儿可以尽快开始上学。","translation":"Good afternoon, Ms Black. Thank you very much for this interview. We arrived in Australia a few months ago and I would like my daughter to start school as soon as possible.","wordCount":32},{"number":3,"speaker":"ENGLISH","text":"We can help you with the enrolment. Firstly, does your child have any health or medical conditions, such as allergies, that we need to be aware of?","wordCount":27},{"number":4,"speaker":"MANDARIN","text":"没有，我女儿很健康，她已经接种了按她的年龄该接种的所有疫苗。她很聪明，已经懂一些英文了。","translation":"No. My daughter is healthy and has received all the vaccines for her age. She is very intelligent and already understands some English.","wordCount":23},{"number":5,"speaker":"ENGLISH","text":"That is great! She will need to do a proficiency test in English to assess whether she may need language support.","wordCount":21},{"number":6,"speaker":"MANDARIN","text":"她的写作仍然不太好。测试是什么样的？如果她的英文不好，她是不是不会被学校录取？她还很小。","translation":"She still can\'t write well. What will the test be like? Would she not be accepted if she doesn\'t perform well in English? She is still very young.","wordCount":28},{"number":7,"speaker":"ENGLISH","text":"Don\'t worry. The test is suitable for her age. It will assess her understanding of English and basic literacy skills according to the year she will be enrolled in.","wordCount":29},{"number":8,"speaker":"MANDARIN","text":"我还想知道她注册需要哪些文件。我不想让她再缺课了。我担心她会跟不上。","translation":"I would also like to know what documents are necessary for her enrolment. I don\'t want her to miss any more classes. I\'m worried that she will lag behind her classmates.","wordCount":31},{"number":9,"speaker":"ENGLISH","text":"We need proof of residential address, such as a utility bill, as well as the child\'s birth certificate and immunisation records. We will also need parents\' details, visa status and passport copies.","wordCount":32},{"number":10,"speaker":"MANDARIN","text":"好。我会把这些文件准备好，这周晚些时候拿过来。我很高兴她能在这学期开始上课。","translation":"Ok. I am going to organise those documents and I will bring them later this week. I\'m very happy that she can start classes this semester.","wordCount":26},{"number":11,"speaker":"ENGLISH","text":"Is there anything else that you would like to know? Please feel free to contact us if you think of anything else later.","wordCount":23},{"number":12,"speaker":"MANDARIN","text":"没有了，就这些。非常感谢您，布莱克女士！","translation":"No, that\'s all for now. Thank you very much, Ms Black.","wordCount":11}],"totalWords":303},{"id":"education-2","domain":"Education","title":"College Computer Course Enrolment","scenario":"This dialogue is a conversation between Tony an English-speaking employee of a local college and a student who has been accepted on a Computer course. The student is speaking with Tony regards the start date of the course and how to pay the fees.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 41 #2059","segments":[{"number":1,"speaker":"ENGLISH","text":"Welcome to the college. I\'m Tony. How can I help you this morning?","wordCount":13},{"number":2,"speaker":"MANDARIN","text":"您好，托尼。我刚被贵校的电脑课程录取。我有一些问题想问一下。","translation":"Hello Tony. I have just been accepted into a computer course here at the college. I have some questions about it.","wordCount":21},{"number":3,"speaker":"ENGLISH","text":"Well done on being accepted! I\'m sure you will enjoy completing the course. What would you like to know?","wordCount":19},{"number":4,"speaker":"MANDARIN","text":"我收到一个电子邮件，里边有一个注册表格的链接。但是在表格上有两个不同的开学日期。我不知道哪一个日期是正确的。","translation":"I received an email with a link to the enrollment form. But there are two different start dates on the form. I don\'t know which date is correct.","wordCount":28},{"number":5,"speaker":"ENGLISH","text":"If you tell me the name of the course, I can check the start date for you. You don\'t want to miss the first day!","wordCount":25},{"number":6,"speaker":"MANDARIN","text":"我非常盼望参加这个课程的学习。要是错过了开学日，那真是太糟糕了。这是一个初级电脑和信息技术支持课程。","translation":"It would be awful to miss the first day, especially as I\'m looking forward to it so much. It\'s the basic computer and IT support course.","wordCount":26},{"number":7,"speaker":"ENGLISH","text":"There are two classes in that course, a full time class and a part time class. That\'s why there are different start dates.","wordCount":23},{"number":8,"speaker":"MANDARIN","text":"哦，我现在明白了！我是被全日制课程录取了。谢谢。","translation":"Oh I understand now! I have been accepted into the full time class. Thank you.","wordCount":15},{"number":9,"speaker":"ENGLISH","text":"You\'re very welcome. It\'s confusing when there are two classes on the form. Tell me what else you need to know.","wordCount":21},{"number":10,"speaker":"MANDARIN","text":"我还想了解一些学费的问题。我可以分期付款吗？","translation":"I also wanted to ask about fees. Can I pay the course fees in installments?","wordCount":15},{"number":11,"speaker":"ENGLISH","text":"Yes, you can. Once you have filled in the enrollment form, you can speak to our finance office to set up a payment plan.","wordCount":24},{"number":12,"speaker":"MANDARIN","text":"这太好了。分期付款比一次性付清要容易多了，因为我是在学习期间做兼职工作。","translation":"That\'s great. It will be much easier to pay for the course in installments rather than all at once. I\'m only working part time while I study.","wordCount":27},{"number":13,"speaker":"ENGLISH","text":"When your enrollment is processed, you will have a student account. You can pay fees through the account and your course information will be listed there too.","wordCount":27},{"number":14,"speaker":"MANDARIN","text":"这听起来很容易。我现在就填写注册表。谢谢您的帮助，托尼。我真希望早点上课！","translation":"That sounds very easy. I will fill in the enrollment form now. Thank you for your help Tony. I can\'t wait to start my course!","wordCount":25}],"totalWords":309},{"id":"employment-1","domain":"Employment","title":"Job Search at JobActive","scenario":"This dialogue is an interview between Jack, a job search case manager, and a job seeker. The interview takes place in Jack\'s office at JobActive.","englishSpeakerGender":"Male","loteSpeakerGender":"Male","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello, I\'m Jack. Thank you for coming in.","wordCount":8},{"number":2,"speaker":"MANDARIN","text":"早上好，杰克！很高兴见到您！上次跟我见面的是穆琳，她是不是今天不在呢？","translation":"Good morning Jack. Nice to meet you. Last time I spoke with Maureen. Isn\'t she in today?","wordCount":17},{"number":3,"speaker":"ENGLISH","text":"She\'s on holidays, but I have already looked at your file and just need to discuss a few things with you.","wordCount":21},{"number":4,"speaker":"MANDARIN","text":"好的，您想讨论些什么？我对没工作这件事越来越担心！每周上两次英语课让我没机会好好找工作。","translation":"OK. What needs to be discussed? I\'m getting more worried about not having a job. English classes twice a week doesn\'t give me a chance to properly look for work.","wordCount":30},{"number":5,"speaker":"ENGLISH","text":"I understand. However, you need to look for 10 jobs a month to continue receiving Centrelink payments. Our network connects job seekers with employers, and we\'ll try to help you.","wordCount":30},{"number":6,"speaker":"MANDARIN","text":"我已经在网上开始找工作了，但要做回我的本行，我需要提高英语口语。","translation":"I\'ve already started looking for jobs online. But to continue in my profession, I need to speak better English.","wordCount":19},{"number":7,"speaker":"ENGLISH","text":"What work did you do before coming to Australia?","wordCount":9},{"number":8,"speaker":"MANDARIN","text":"我以前是计算机技术人员，负责系统管理和编程。","translation":"I worked as a computer technician and was responsible for systems administration and programming.","wordCount":14},{"number":9,"speaker":"ENGLISH","text":"You should try other areas until you\'re stronger in English. Your previous experience may be useful. Some companies offer training in areas where you may not need 100% English fluency.","wordCount":32},{"number":10,"speaker":"MANDARIN","text":"如果您可以安排让我去 IT 公司面试就太好了！这样我就有机会继续留在计算机这一行业。","translation":"It would be fantastic if you could arrange interviews for me with IT organisations. I\'d have the opportunity to continue in the field of computing.","wordCount":25},{"number":11,"speaker":"ENGLISH","text":"We\'ll see. You must prepare a r\xe9sum\xe9. We can help you write one.","wordCount":13},{"number":12,"speaker":"MANDARIN","text":"谢谢。您能帮助我使用寻工服务和网上招工列表吗？","translation":"Thank you. Can you also help me use the Job Services and the online job listing?","wordCount":16},{"number":13,"speaker":"ENGLISH","text":"Definitely. You can also use the job search tools in the Centrelink computers. We\'ll schedule another interview for next week and finalise the finer points.","wordCount":25},{"number":14,"speaker":"MANDARIN","text":"我感到更有希望、更乐观了！我要去买一件初次面试时穿的新衬衫。我要赶快走了，上课要迟到了。再见！","translation":"I\'m more hopeful and more optimistic! I\'ll even buy a new shirt for the first interview. I need to run now not to be late for my class. Bye!","wordCount":29},{"number":15,"speaker":"ENGLISH","text":"We\'ll select available jobs and next time we may have good news and you\'ll be able to wear your new shirt. Bye!","wordCount":22}],"totalWords":310},{"id":"employment-2","domain":"Employment","title":"Part-time Campus Job Inquiry","scenario":"This dialogue is a conversation between a university student and Mark, an English-speaking Student advisor at the student centre about jobs. The student would like to get a part time job on campus to help pay for expenses.","englishSpeakerGender":"Male","loteSpeakerGender":"Either","testId":"2019 Test 39 #2056","segments":[{"number":1,"speaker":"ENGLISH","text":"Hi, welcome to the university student centre. My name is Mark. How can I help you today?","wordCount":17},{"number":2,"speaker":"MANDARIN","text":"你好，马克。我想询问一下关于学生找工作的事情。我的朋友说在校园内可能有工作。","translation":"Hi Mark. I\'m enquiring about jobs for students. A friend mentioned that there may be work available on campus.","wordCount":19},{"number":3,"speaker":"ENGLISH","text":"The university has an employment website which lists all job vacancies on campus. There are full time and part time jobs available.","wordCount":22},{"number":4,"speaker":"MANDARIN","text":"我在找兼职的工作。我觉得我无法应付全职工作，我的课程非常繁重。","translation":"I am looking for a part time job. I don\'t think I would be able to manage a full time job. My course is very demanding.","wordCount":26},{"number":5,"speaker":"ENGLISH","text":"I understand. I know it\'s very hard for students to work full time and study. That\'s why part time jobs on campus are so popular.","wordCount":25},{"number":6,"speaker":"MANDARIN","text":"兼职工作多吗？我想尽快找到工作来帮补生活开支。我在多个领域有工作经验。","translation":"Are there many part time jobs available? I would like to find work as soon as possible to help with my living expenses. I have experience in several areas.","wordCount":29},{"number":7,"speaker":"ENGLISH","text":"The university is currently taking applications for waiters and kitchen staff to work in the function centre. Have you had any experience working at cafes or restaurants?","wordCount":27},{"number":8,"speaker":"MANDARIN","text":"我在一家咖啡厅当过服务员。我也做过厨房帮工。你能提供更详细的信息吗？或者我应该浏览一下大学的网站？","translation":"I have had some experience as a waiter in a cafe. I have also worked as a kitchenhand. Do you have more information, or should I look on the university website?","wordCount":31},{"number":9,"speaker":"ENGLISH","text":"I can give you some information, but you will need to look at the website for all the details. You also apply for jobs on the website.","wordCount":27},{"number":10,"speaker":"MANDARIN","text":"那太好了。今天晚些时候我会浏览一下网站，顺便申请适合我的工作。","translation":"That\'s great. I will look at the website later today and put in an application for any jobs that are suitable.","wordCount":21},{"number":11,"speaker":"ENGLISH","text":"Good luck. If you miss out on getting a job at the function centre this time, keep checking the website. New jobs are listed regularly.","wordCount":25},{"number":12,"speaker":"MANDARIN","text":"我会这么做的。希望不久我就能找到新工作。感谢你的帮助！","translation":"I will do that. I\'m hoping it won\'t be long before I have a new job. Thank you for helping me!","wordCount":21}],"totalWords":290},{"id":"financial","domain":"Financial","title":"Home Loan Application at Bank","scenario":"This dialogue takes place between Mr Wilson, a loan manager at a Sydney Bank and a client who has made an appointment to see him. The client wants to purchase a property and is enquiring about how to apply for a loan.","englishSpeakerGender":"Male","loteSpeakerGender":"Female","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello, my name is Justin Wilson. I understand you are booked in with me today to discuss a loan, is that right?","wordCount":22},{"number":2,"speaker":"MANDARIN","text":"没错!我终于找到了一间价格合理的公寓，我想买下来，所以我有几个问题。","translation":"Yes, that\'s right. I finally found an apartment for a decent price and I\'m thinking of buying it, so I have a few questions.","wordCount":24},{"number":3,"speaker":"ENGLISH","text":"You\'ve come to the right place. How can I help?","wordCount":10},{"number":4,"speaker":"MANDARIN","text":"我想知道如何获得贷款，利率是多少，需要多少首付。","translation":"I would like to know how to obtain financing, what is the interest rate and how much deposit is needed.","wordCount":20},{"number":5,"speaker":"ENGLISH","text":"I can certainly assist you with all that. How about we start by talking about the property you are interested in?","wordCount":21},{"number":6,"speaker":"MANDARIN","text":"好啊。","translation":"Yes, perfect.","wordCount":2},{"number":7,"speaker":"ENGLISH","text":"What caught your eye in this property? And how much is it valued at?","wordCount":14},{"number":8,"speaker":"MANDARIN","text":"是一套非常小的两卧室公寓。地板是最近翻新的，位置很不错，靠近我需要的一切。","translation":"It is a very small two-bedroom apartment. The floor has been recently renovated and the location is great, near everything I need.","wordCount":23},{"number":9,"speaker":"ENGLISH","text":"Fantastic. Do you have the financial details for the property, such as the price and rates?","wordCount":16},{"number":10,"speaker":"MANDARIN","text":"房地产中介的女士说，业主会考虑接受 60 万以上的出价。这有点超出我的预算，但这套公寓很难得。","translation":"The lady from the real estate agency said the owner is accepting offers above $600,000. It is a little over what I had planned, but it is a great find.","wordCount":33},{"number":11,"speaker":"ENGLISH","text":"Certainly. We need to work out if you have enough savings for the deposit and whether you can borrow the rest.","wordCount":21},{"number":12,"speaker":"MANDARIN","text":"这套房子需要多少首付？","translation":"And how much would the deposit for this property be?","wordCount":10},{"number":13,"speaker":"ENGLISH","text":"You need at least 10% of the total value, plus enough to cover other rates and expenses.","wordCount":18},{"number":14,"speaker":"MANDARIN","text":"好的，跟我想的差不多。我有 7 万块存款可以用来付首付和杂费。那银行会借给我剩下的部分吗？","translation":"Ok, that is what I figured. I already have $70,000 saved to cover the deposit and fees. Will the bank lend me the rest?","wordCount":26},{"number":15,"speaker":"ENGLISH","text":"Let\'s use our loan calculator to work out how much you can borrow. I need to ask you some personal questions in order to assess your income.","wordCount":27},{"number":16,"speaker":"MANDARIN","text":"当然可以！我今天把所有文件都带来了，这样我们马上就可以开始。","translation":"Of course. I gathered all my documents and brought them with me today so that we can get started straight away.","wordCount":21}],"totalWords":308},{"id":"social-services","domain":"Social Services","title":"Centrelink Youth Allowance","scenario":"This dialogue takes place over the phone between a mother and a Centrelink Social Worker, Melinda. Melinda wants to discuss the son\'s application for Youth Allowance. The son has told Melinda that he cannot live with his Mum and is applying for the Living Away from Home Allowance because of conflict in the home.","englishSpeakerGender":"Female","loteSpeakerGender":"Female","testId":"2019","segments":[{"number":1,"speaker":"ENGLISH","text":"Hello, my name is Melinda, I\'m a social worker at Centrelink. Do you have a minute to talk about your son?","wordCount":21},{"number":2,"speaker":"MANDARIN","text":"我正准备去超市，但可以等下再去。我儿子怎么了？","translation":"I was just about to go to the supermarket but it can wait. Has something happened to my son?","wordCount":19},{"number":3,"speaker":"ENGLISH","text":"Everything is fine. Your son has applied for Youth Allowance and I need to speak to you about his circumstances. He said that you had an argument and you told him to leave the house.","wordCount":35},{"number":4,"speaker":"MANDARIN","text":"是的，我们吵了一架。我告诉他，住在我家里时，必须规矩点，不要再跟他的一些朋友见面。我听说他们跟毒品有关。","translation":"Yes, we had an argument and I told him that while he is living under my roof he has to behave and stop seeing some of his friends. I heard they are involved with drugs.","wordCount":35},{"number":5,"speaker":"ENGLISH","text":"Well, your son told me a slightly different story. He said that he wasn\'t allowed to return home, so I was considering granting him Youth Allowance at the Living Away from Home rate.","wordCount":33},{"number":6,"speaker":"MANDARIN","text":"只有他不规矩时才不让他回家！我是单身，还有另外两个孩子要照顾。生活虽然很艰难，但我的门总是对他敞开着。我只是希望他安全。","translation":"Only if he doesn\'t behave! I\'m on my own with another 2 children to look after. Life\'s tough right now but my door is always open for him. I just want him to be safe.","wordCount":35},{"number":7,"speaker":"ENGLISH","text":"It sounds like it\'s been hard for you bringing up 3 children on your own. Would you like to come into the office to discuss a few options on how we could help you?","wordCount":34},{"number":8,"speaker":"MANDARIN","text":"我没时间去你们办公室。我每天工作几个小时，还要去学校接孩子。","translation":"I don\'t have time to go to the office. I work a few hours every day and then I have to pick up my children from school.","wordCount":27},{"number":9,"speaker":"ENGLISH","text":"How about over the phone? I can refer you to some services, like mediation, parent support groups and community organisations.","wordCount":20},{"number":10,"speaker":"MANDARIN","text":"好的，我们可以预约后天，在我去学校接完孩子以后。","translation":"OK, we can make an appointment for the day after tomorrow after I pick up the kids from school.","wordCount":19},{"number":11,"speaker":"ENGLISH","text":"How does 3.30 sound?","wordCount":5},{"number":12,"speaker":"MANDARIN","text":"3:30可以。这样我有时间为孩子们准备点心，他们到家时总是觉得饿。","translation":"3:30 is OK. That gives me time to make a snack for the kids; they are always starving when they get home!","wordCount":23}],"totalWords":306}]')}}]);